from dag.backfill import plan_backfill

def test_backfills_the_missed_days():
    assert plan_backfill("2026-02-24", "2026-02-27") == ["2026-02-25", "2026-02-26"]

def test_no_gap_returns_empty():
    assert plan_backfill("2026-02-26", "2026-02-27") == []

