from dag.recovery import idempotent_load

def test_rerunning_a_day_does_not_duplicate():
    table = {}
    rows = [{"id": 1}, {"id": 2}]
    idempotent_load(table, "2026-02-25", rows)
    idempotent_load(table, "2026-02-25", rows)   # backfill re-runs the same day
    assert table["2026-02-25"] == rows

def test_independent_partitions_coexist():
    table = {}
    idempotent_load(table, "2026-02-25", [{"id": 1}])
    idempotent_load(table, "2026-02-26", [{"id": 2}])
    assert table["2026-02-25"] == [{"id": 1}]
    assert table["2026-02-26"] == [{"id": 2}]

