from dag.pipeline import should_publish

def test_does_not_publish_when_quality_fails():
    assert should_publish(quality_passed=False, load_succeeded=True) is False

def test_publishes_when_load_and_quality_pass():
    assert should_publish(quality_passed=True, load_succeeded=True) is True
